        return
      }

      const throwFileSizeLimit = typeof options.throwFileSizeLimit === 'boolean'
        ? options.throwFileSizeLimit
        : defaultThrowFileSizeLimit

      const value = {
        fieldname: name,
        filename,
        encoding,
        mimetype,
        file,
        fields: body,
        _buf: null,
        async toBuffer () {
          if (this._buf) {
            return this._buf
          }
