			lmp->u.value[i+buff_len] = lmp->u.value[i];

		memcpy(lmp->u.value,buff,buff_len);

		lmp->len += buff_len;

	}

	if( op == ADD_TO_BACK && buff_len >0 )
	{

		lmp->u.value = (char*)pkg_realloc(lmp->u.value, lmp->len+buff_len);
		if(!lmp->u.value) {
			LM_ERR("No more pkg memory\n");
